// This driver demonstrates how test cases are processed for a program that reads from stdin and writes to stdout.
// In a real testing environment, the student's compiled executable would be run for each test case.
// The driver typically contains the reference solution to generate expected outputs.

#include <iostream>
#include <string>
#include <sstream>
#include <limits> // For numeric_limits

long long calculate_correct_factorial(int n) {
    if (n < 0) return -1; // Special value for error condition
    if (n == 0) return 1;
    long long res = 1;
    for (int i = 1; i <= n; ++i) {
        // Check for overflow before multiplication
        if (std::numeric_limits<long long>::max() / i < res) {
            return -2; // Special value for overflow
        }
        res *= i;
    }
    return res;
}

int main() {
    // Example of a single test case execution:
    int test_input = 5;
    long long expected_factorial = calculate_correct_factorial(test_input);

    std::cout << "// Input: " << test_input << std::endl;
    if (expected_factorial == -1) {
        std::cout << "// Expected Output: Factorial is not defined for negative numbers." << std::endl;
    } else if (expected_factorial == -2) {
        std::cout << "// Expected Output: (Value too large to fit in long long, indicating overflow)" << std::endl;
    } else {
        std::cout << "// Expected Output: Factorial of " << test_input << " is " << expected_factorial << std::endl;
    }

    std::cout << "// The student's program's actual output would be captured and compared to this expected output." << std::endl;
    return 0;
}
